"""
core/odb_parser.py
──────────────────
Parses ODB++ fabrication data to extract component placement with
**exact pin-1 positions** — giving 99%-confidence polarity markers.

The actual data lives in:
    steps/pcb/layers/comp_+_top/components   (top-side components)
    steps/pcb/layers/comp_+_bot/components   (bottom-side components)

Format (KiCad ODB++ v7+)::

    CMP <pkg_idx> <x> <y> <rotation> <N/Y> <refdes> <package> ;0=<mount>
    PRP <key> '<value>'
    TOP <pad_idx> <abs_x> <abs_y> <rot> <N/Y> <net_id> <subnet> <pin_number>

The TOP lines give **absolute** pad coordinates in mm — no rotation
needed.  pin_number (last field) is the 1-based pin number.
"""
from __future__ import annotations

import os
import re
import tarfile
import zipfile
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple

from utils.geometry import BoundingBox, Point
from core.component_detector import Component, _PATTERNS, POLAR_TYPES
from core.polarity_detector import PolarityMarker

MM_TO_PT: float = 72.0 / 25.4
INCH_TO_PT: float = 72.0

# Net name keywords that identify the cathode (GND) side of a diode
_GND_KEYWORDS = ("GND", "VSS", "AGND", "PGND", "DGND", "0V", "EARTH",
                 "SGND", "CHASSIS", "PE", "SHIELD")
# Net name keywords that identify the anode (supply) side
_VCC_KEYWORDS = ("VCC", "VDD", "VIN", "VBUS", "VSUPPLY", "VMOT",
                 "+5V", "+3V3", "+3.3V", "+12V", "+24V", "+48V", "AVCC")


# ─────────────────────────────────────────────────────────────────────────────
# Internal data classes
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class _ODBPin:
    number: int     # 1-based pin number (0 if non-numeric name)
    x: float        # absolute X in source units
    y: float        # absolute Y in source units
    net_id: int = 0 # net index (used for cathode detection via netlist)
    name: str = ""  # pin identifier suffix: "1", "A", "K", "G", "S", "D", "P1", ...


@dataclass
class _ODBComponent:
    ref: str
    x: float            # centre X in source units
    y: float            # centre Y in source units
    rotation: float     # degrees
    mirrored: bool
    side: str = "top"   # "top" or "bot"
    pins: List[_ODBPin] = field(default_factory=list)
    package: str = ""   # PKG_TYPE from PRP line (IPC-7351 footprint name)
    description: str = ""  # PRP Description value

    # Set by resolve_polarity() — None means use heuristic
    _cathode_pin_num: Optional[int] = field(default=None, repr=False)
    _cathode_pin_name: Optional[str] = field(default=None, repr=False)

    def resolve_polarity(self, net_map: Dict[int, str]) -> None:
        """Use net names from the ODB++ netlist to find the cathode pin.

        Searches each pin's net name for GND-type keywords (→ cathode) or
        VCC-type keywords (→ anode, so the *other* pin is cathode).
        Only applied to diodes and LEDs.
        """
        if self.comp_type not in ("diode", "led"):
            return
        if len(self.pins) < 2:
            return

        # Pass 1: direct GND keyword → that pin is cathode
        for pin in self.pins:
            nm = net_map.get(pin.net_id, "").upper()
            if any(kw in nm for kw in _GND_KEYWORDS):
                self._cathode_pin_num = pin.number
                self._cathode_pin_name = pin.name
                return

        # Pass 2: VCC keyword → the other pin is cathode
        for pin in self.pins:
            nm = net_map.get(pin.net_id, "").upper()
            if any(kw in nm for kw in _VCC_KEYWORDS):
                others = [p for p in self.pins if p.number != pin.number]
                if others:
                    self._cathode_pin_num = others[0].number
                    self._cathode_pin_name = others[0].name
                    return

    @property
    def pin1(self) -> Optional[_ODBPin]:
        for p in self.pins:
            if p.number == 1:
                return p
        return self.pins[0] if self.pins else None

    @property
    def pin2(self) -> Optional[_ODBPin]:
        for p in self.pins:
            if p.number == 2:
                return p
        return None

    @property
    def polarity_pin(self) -> Optional[_ODBPin]:
        """Pin to mark for polarity.

        - Diodes / LEDs: the cathode pin determined by:
            1. Net-name lookup (most reliable, via resolve_polarity())
            2. Functional pin name: 'K', 'KA', 'CAT', 'CATH', 'CATHODE', 'NEG'
            3. Anode identified → other pin is cathode: 'A', 'AN', 'ANODE', 'POS'
            4. Fallback: pin 2 (standard SMD diode convention: pin1=anode, pin2=cathode)
        - Transistors: gate/base pin ('G', 'GATE', 'B', 'BASE') or pin 1
        - All other components: pin 1.
        """
        if self.comp_type in ("diode", "led"):
            # 1. Net-name lookup — match by stored name first, then by number
            if self._cathode_pin_name is not None:
                for p in self.pins:
                    if p.name == self._cathode_pin_name:
                        return p
            if self._cathode_pin_num is not None:
                for p in self.pins:
                    if p.number == self._cathode_pin_num:
                        return p
            # 2. Functional cathode names
            for p in self.pins:
                if p.name.upper() in _CATHODE_NAMES:
                    return p
            # 3. Functional anode names → other pin is cathode
            for p in self.pins:
                if p.name.upper() in _ANODE_NAMES:
                    others = [x for x in self.pins if x is not p]
                    if others:
                        return others[0]
            # 4. Fallback: pin 2 = cathode
            return self.pin2 or self.pin1

        if self.comp_type == "transistor":
            # Gate / base = control pin for polarity marking
            for p in self.pins:
                if p.name.upper() in _GATE_NAMES:
                    return p
            return self.pin1

        return self.pin1

    @property
    def pin_span_mm(self) -> float:
        """Max span between pin positions in source units."""
        if len(self.pins) < 2:
            return 0.0
        xs = [p.x for p in self.pins]
        ys = [p.y for p in self.pins]
        return max(max(xs) - min(xs), max(ys) - min(ys))

    @property
    def comp_type(self) -> str:
        for ctype, pat in _PATTERNS.items():
            if pat.match(self.ref):
                return ctype
        return "unknown"

    @property
    def is_polar(self) -> bool:
        ctype = self.comp_type
        if ctype not in POLAR_TYPES:
            return False
        if ctype == "capacitor" and self._is_ceramic_cap():
            return False
        return True

    def _is_ceramic_cap(self) -> bool:
        pkg = self.package.upper()
        desc = self.description.upper()

        # Determine if description suggests an electrolytic/polar capacitor:
        # "POLARIZED" is only electrolytic if NOT preceded by "UN"
        _ELEC_DESC_KW = ("ELKO", "ALU-ELKO", "ALUM", "TANT", "ELECTROLYTIC",
                         "EL.CAP", "ALUMINIUM", "ALUMINUM", "POLYMER")
        is_elec_desc = any(kw in desc for kw in _ELEC_DESC_KW)
        if "POLARIZED" in desc and "UNPOLAR" not in desc:
            is_elec_desc = True

        # If description strongly suggests electrolytic → NOT ceramic
        if is_elec_desc:
            return False

        if pkg:
            # Standard IPC-7351 chip capacitor prefixes
            if pkg.startswith("CAPC") or pkg.startswith("CAPMP"):
                return True
            # Electrolytic / polar body types (package name contains these)
            _ELEC_PKG_KW = ("EL", "POL", "TANT", "ELKO", "ECAP", "ALUM",
                            "CAP_EL", "CAP_AL")
            if any(kw in pkg for kw in _ELEC_PKG_KW):
                return False
            # Electrolytic package shape prefixes (IPC-7351 radial/axial)
            if pkg.startswith(("CAPPR", "CAPE", "CAPT", "CP_ELEC", "CP_TANT")):
                return False
            # Standard SMD chip sizes (Altium/other CAD tool Body format)
            # These are all non-polar ceramic capacitor package designators
            _CHIP_SIZES = {"0201", "0402", "0603", "0805", "1206", "1210",
                           "1812", "2512", "1805", "0303", "0606", "1616"}
            if pkg in _CHIP_SIZES or any(pkg.startswith(s) for s in _CHIP_SIZES):
                return True
            # MLCC / ceramic keyword in package name
            if "MLCC" in pkg or pkg.startswith("CHIPLED"):
                return True

        # Fallback heuristic: 2 pins + small pitch → assume ceramic
        if len(self.pins) == 2 and self.pin_span_mm < 5.0:
            _elec_pkg_kw = ("EL", "POL", "TANT", "ELKO", "ECAP", "ALUM")
            if not any(kw in pkg for kw in _elec_pkg_kw) and not is_elec_desc:
                return True
        return False


# ─────────────────────────────────────────────────────────────────────────────
# Regex patterns for comp_+_top/components format
# ─────────────────────────────────────────────────────────────────────────────

# CMP <pkg_idx> <x> <y> <rotation> <N/Y> <refdes> <package> ;...
_RE_CMP = re.compile(
    r"^CMP\s+\d+\s+"
    r"([\d.eE+-]+)\s+([\d.eE+-]+)\s+"
    r"([\d.eE+-]+)\s+"
    r"([NY])\s+"
    r"(\S+)\s+"
    r"(\S+)",
    re.IGNORECASE,
)

# TOP <pad_idx> <abs_x> <abs_y> <rot> <N/Y> <net_id> <subnet> <pin_name>
# pin_name may be a plain integer ("1"), a functional name ("A","K","G","S","D"),
# or a REFDES-PINNAME string ("IC700-1", "D804-A", "D804-K").
_RE_TOP = re.compile(
    r"^TOP\s+\d+\s+"
    r"([\d.eE+-]+)\s+([\d.eE+-]+)\s+"  # x, y
    r"[\d.eE+-]+\s+"                    # rotation (skip)
    r"[NY]\s+"                          # mirrored (skip)
    r"(\d+)\s+\d+\s+"                  # net_id (capture), subnet (skip)
    r"(\S+)",                           # pin_name — may be "1","A","K","IC700-1", etc.
    re.IGNORECASE,
)

# PRP PKG_TYPE 'value'  ← KiCad / Altium "PKG_TYPE"
# PRP Body 'value'      ← Altium "Body" field
_RE_PRP_PKG = re.compile(r"^PRP\s+(?:PKG_TYPE|Body)\s+'([^']*)'", re.IGNORECASE)

# PRP Description 'value'           ← KiCad
# PRP ShortDesription 'value'       ← Altium (note typo in spec)
# PRP ShortDescription 'value'      ← Altium (correctly spelled)
# PRP Bezeichnung 'value'           ← German CAD tools
_RE_PRP_DESC = re.compile(
    r"^PRP\s+(?:Description|ShortDesription|ShortDescription|Bezeichnung)\s+'([^']*)'",
    re.IGNORECASE,
)


# ─────────────────────────────────────────────────────────────────────────────
# Functional pin name sets (used for polarity detection)
# ─────────────────────────────────────────────────────────────────────────────

# Pin names that indicate the CATHODE side of a diode/LED
_CATHODE_NAMES = frozenset({"K", "KA", "CAT", "CATH", "CATHODE", "NEG"})
# Pin names that indicate the ANODE side (the OTHER pin is cathode)
_ANODE_NAMES   = frozenset({"A", "AN", "ANODE", "POS"})
# Pin names that indicate the gate/base of a transistor
_GATE_NAMES    = frozenset({"G", "GATE", "B", "BASE"})


# ─────────────────────────────────────────────────────────────────────────────
# Pin name helpers
# ─────────────────────────────────────────────────────────────────────────────

def _pin_suffix(raw_name: str) -> str:
    """Extract the pin identifier from an ODB++ pin name.

    Two common formats:
      - Plain:        '1', '2', 'A', 'K', 'G', 'P1'
      - RefDes-Pin:   'D804-A', 'IC700-1', 'IC700-P1'  → strip refdes prefix
    """
    if '-' in raw_name:
        return raw_name.rsplit('-', 1)[-1]
    return raw_name


def _pin_num(suffix: str) -> int:
    """Convert a pin suffix string to an integer pin number.

    'A', 'K', 'G', 'S', 'D' → 0  (functional names, not numbered)
    '1', '2', '3'            → 1, 2, 3
    'P1', 'P2'               → 1, 2  (thermal pad)
    '1A', '1B'               → 1     (multi-section)
    """
    if suffix.isdigit():
        return int(suffix)
    # P<n> thermal pad
    if len(suffix) > 1 and suffix[0].upper() == 'P' and suffix[1:].isdigit():
        return int(suffix[1:])
    # Leading digits (e.g. "1A", "1B")
    m = re.match(r'^(\d+)', suffix)
    if m:
        return int(m.group(1))
    return 0  # functional name — not a numbered pin


# ─────────────────────────────────────────────────────────────────────────────
# Parser
# ─────────────────────────────────────────────────────────────────────────────

class ODBParser:
    """
    Parses ODB++ and returns ``MatchResult`` per component.
    Accepts .zip, .tgz/.tar.gz, or unzipped directory.
    """

    def parse(self, path: str) -> "List[MatchResult]":
        from core.matcher import MatchResult
        odb_comps, scale = self._load(path)
        return self._build_results(odb_comps, scale)

    def _load(self, path: str) -> Tuple[List[_ODBComponent], float]:
        low = path.lower()
        if os.path.isfile(path) and low.endswith(".zip"):
            return self._from_zip(path)
        elif os.path.isfile(path) and (
            low.endswith(".tgz") or low.endswith(".tar.gz") or low.endswith(".tar")
        ):
            return self._from_tgz(path)
        elif os.path.isdir(path):
            return self._from_dir(path)
        else:
            raise ValueError(f"Unsupported ODB++ path: {path}")

    # ── ZIP ───────────────────────────────────────────────────────────────

    def _from_zip(self, zip_path: str) -> Tuple[List[_ODBComponent], float]:
        with zipfile.ZipFile(zip_path, "r") as zf:
            names = zf.namelist()
            comps: List[_ODBComponent] = []
            scale = MM_TO_PT

            # Build net map from cadnet netlist
            net_map = {}
            for netlist_path in ("netlists/cadnet/netlist",):
                nl_cands = [n for n in names if n.lower().endswith(netlist_path)]
                if nl_cands:
                    net_map = self._parse_netlist(
                        zf.read(nl_cands[0]).decode("utf-8", errors="replace")
                    )
                    break

            for side in ("top", "bot"):
                pattern = f"comp_+_{side}/components"
                candidates = [n for n in names if n.endswith(pattern)]
                if not candidates:
                    continue
                content = zf.read(candidates[0]).decode("utf-8", errors="replace")
                scale = self._detect_scale(content)
                batch = self._parse_components(content, side)
                for c in batch:
                    c.resolve_polarity(net_map)
                comps.extend(batch)
            if not comps:
                raise FileNotFoundError(
                    f"No comp_+_top/components found in ZIP.\n"
                    f"Contents: {names[:30]}"
                )
        return comps, scale

    # ── TGZ ───────────────────────────────────────────────────────────────

    def _from_tgz(self, tgz_path: str) -> Tuple[List[_ODBComponent], float]:
        mode = "r:gz" if (tgz_path.lower().endswith(".gz") or
                          tgz_path.lower().endswith(".tgz")) else "r"
        with tarfile.open(tgz_path, mode) as tf:
            names = tf.getnames()
            comps: List[_ODBComponent] = []
            scale = MM_TO_PT

            # Build net map from cadnet netlist
            net_map = {}
            for netlist_suffix in ("netlists/cadnet/netlist",):
                nl_cands = [n for n in names
                            if n.lower().replace("\\", "/").endswith(netlist_suffix)]
                if nl_cands:
                    f = tf.extractfile(tf.getmember(nl_cands[0]))
                    if f:
                        net_map = self._parse_netlist(
                            f.read().decode("utf-8", errors="replace")
                        )
                    break

            for side in ("top", "bot"):
                pattern = f"comp_+_{side}/components"
                candidates = [n for n in names if n.endswith(pattern)]
                if not candidates:
                    continue
                f = tf.extractfile(tf.getmember(candidates[0]))
                content = f.read().decode("utf-8", errors="replace")
                scale = self._detect_scale(content)
                batch = self._parse_components(content, side)
                for c in batch:
                    c.resolve_polarity(net_map)
                comps.extend(batch)
            if not comps:
                raise FileNotFoundError(
                    f"No comp_+_top/components in TGZ.\nContents: {names[:30]}"
                )
        return comps, scale

    # ── Directory ─────────────────────────────────────────────────────────

    def _from_dir(self, dir_path: str) -> Tuple[List[_ODBComponent], float]:
        comps: List[_ODBComponent] = []
        scale = MM_TO_PT
        net_map = {}

        # Try to find cadnet netlist
        for root, _dirs, files in os.walk(dir_path):
            if "netlist" in files and "cadnet" in root.lower():
                fpath = os.path.join(root, "netlist")
                try:
                    with open(fpath, encoding="utf-8", errors="replace") as fh:
                        net_map = self._parse_netlist(fh.read())
                except Exception:
                    pass
                break

        for side in ("top", "bot"):
            for root, _dirs, files in os.walk(dir_path):
                dirname = os.path.basename(root).lower()
                if dirname == f"comp_+_{side}" and "components" in files:
                    fpath = os.path.join(root, "components")
                    with open(fpath, encoding="utf-8", errors="replace") as fh:
                        content = fh.read()
                    scale = self._detect_scale(content)
                    batch = self._parse_components(content, side)
                    for c in batch:
                        c.resolve_polarity(net_map)
                    comps.extend(batch)
        if not comps:
            raise FileNotFoundError(f"No comp_+_top/components under: {dir_path}")
        return comps, scale

    # ── Unit detection ────────────────────────────────────────────────────

    @staticmethod
    def _detect_scale(content: str) -> float:
        for line in content.splitlines()[:15]:
            stripped = line.strip().upper()
            if stripped.startswith("UNITS"):
                if "INCH" in stripped:
                    return INCH_TO_PT
                return MM_TO_PT
        return MM_TO_PT

    # ── Netlist parser (cadnet format: "$0 NET_NAME") ─────────────────────

    @staticmethod
    def _parse_netlist(content: str) -> Dict[int, str]:
        """Parse ODB++ cadnet netlist → {net_id: net_name}."""
        net_map: Dict[int, str] = {}
        for line in content.splitlines():
            line = line.strip()
            if not line or line.startswith("#") or line.startswith("H "):
                continue
            if line.startswith("$"):
                parts = line.split(None, 1)
                if len(parts) == 2:
                    try:
                        net_map[int(parts[0][1:])] = parts[1].strip()
                    except ValueError:
                        pass
        return net_map

    # ── Component file parser ─────────────────────────────────────────────

    @staticmethod
    def _parse_components(content: str, side: str) -> List[_ODBComponent]:
        components: List[_ODBComponent] = []
        current: Optional[_ODBComponent] = None

        for raw_line in content.splitlines():
            line = raw_line.strip()
            if not line or line.startswith("#"):
                continue

            m = _RE_CMP.match(line)
            if m:
                current = _ODBComponent(
                    ref=m.group(5),
                    x=float(m.group(1)),
                    y=float(m.group(2)),
                    rotation=float(m.group(3)),
                    mirrored=(m.group(4).upper() == "Y"),
                    side=side,
                    package=m.group(6),  # initial: footprint/partnum from CMP line
                )
                components.append(current)
                continue

            if current is None:
                continue

            # Parse PKG_TYPE property
            mp = _RE_PRP_PKG.match(line)
            if mp:
                current.package = mp.group(1)
                continue

            # Parse Description property
            md = _RE_PRP_DESC.match(line)
            if md:
                current.description = md.group(1)
                continue

            # Parse TOP line (pad / pin)
            m = _RE_TOP.match(line)
            if m:
                raw_pin_name = m.group(4)           # e.g. "D804-A", "IC700-1", "1"
                suffix = _pin_suffix(raw_pin_name)  # e.g. "A",      "1",       "1"
                num    = _pin_num(suffix)            # e.g.  0,        1,         1
                current.pins.append(_ODBPin(
                    x=float(m.group(1)),
                    y=float(m.group(2)),
                    net_id=int(m.group(3)),
                    number=num,
                    name=suffix,
                ))
        return components

    # ── Build MatchResult ─────────────────────────────────────────────────

    @staticmethod
    def _build_results(
        odb_comps: List[_ODBComponent],
        unit_scale: float = MM_TO_PT,
    ) -> "List[MatchResult]":
        from core.matcher import MatchResult

        results = []
        for oc in odb_comps:
            cx_pt = oc.x * unit_scale
            cy_pt = oc.y * unit_scale
            page_idx = 0 if oc.side == "top" else 1
            comp = Component(
                ref=oc.ref,
                comp_type=oc.comp_type,
                bbox=BoundingBox(cx_pt - 3, cy_pt - 3, cx_pt + 3, cy_pt + 3),
                center=Point(cx_pt, cy_pt),
                page=page_idx,
            )
            p_pin = oc.polarity_pin
            if p_pin is not None and oc.is_polar:
                p1x = p_pin.x * unit_scale
                p1y = p_pin.y * unit_scale
                mtype = "cathode_odb" if oc.comp_type in ("diode", "led") else "pin1_odb"
                marker = PolarityMarker(
                    marker_type=mtype,
                    bbox=BoundingBox(p1x - 2, p1y - 2, p1x + 2, p1y + 2),
                    center=Point(p1x, p1y),
                    page=page_idx,
                    confidence=0.99,
                    source="odb",
                )
                results.append(MatchResult(
                    component=comp,
                    markers=[marker],
                    polarity_status="marked",
                    overall_confidence=0.99,
                ))
            else:
                results.append(MatchResult(
                    component=comp,
                    polarity_status="unmarked",
                ))
        return results


# ─────────────────────────────────────────────────────────────────────────────
# Convenience functions
# ─────────────────────────────────────────────────────────────────────────────

def parse_odb(path: str) -> "List[MatchResult]":
    return ODBParser().parse(path)


def parse_odb_raw(path: str):
    """Return (odb_components, unit_scale) for coordinate registration."""
    return ODBParser()._load(path)

"""
core/odb_silk_cathode.py
────────────────────────
Detect diode / LED cathode pins by analysing the ODB++ silkscreen layer.

For each 2-pin diode/LED component the algorithm:
  1. Reads silk-layer line features near the component footprint.
  2. Projects each feature's midpoint onto the pin-to-pin axis.
  3. Scores each pin half by total feature "mass" (length × width),
     boosted 3.5× for features running perpendicular to the axis
     (= cathode band candidates).
  4. Declares the heavier half the cathode when its ratio > _MIN_RATIO.

Returns a dict {ref: pin_index} where pin_index is 0 or 1
(index into _ODBComponent.pins[]).  Returns {} on any error so
callers can fall back to other detection methods without crashing.
"""
from __future__ import annotations

import math
import os
import re
import tarfile
import zipfile
from typing import Dict, Optional, Tuple

# ─────────────────────────────────────────────────────────────────────────────
# Tuning constants
# ─────────────────────────────────────────────────────────────────────────────

_MIN_RATIO = 0.55   # cathode side must hold this fraction of total silk mass
_MIN_MASS  = 0.02   # minimum total silk mass (mm²) required for a decision


# ─────────────────────────────────────────────────────────────────────────────
# Public API
# ─────────────────────────────────────────────────────────────────────────────

def detect_cathodes(odb_path: str, odb_comps: list) -> Dict[str, int]:
    """Return {ref: pin_index} for diodes/LEDs whose cathode can be inferred
    from silkscreen geometry.  *pin_index* is 0 or 1 (into comp.pins[]).

    Silently returns {} if the archive cannot be read, no silk layer exists,
    or scores are inconclusive.
    """
    try:
        return _detect_impl(odb_path, odb_comps)
    except Exception:
        return {}


# ─────────────────────────────────────────────────────────────────────────────
# Archive I/O
# ─────────────────────────────────────────────────────────────────────────────

def _is_relevant(key: str) -> bool:
    """Return True for paths we need to read (matrix + layer features)."""
    return (
        (key.endswith("/features") and "/layers/" in key)
        or key.endswith("matrix/matrix")
    )


def _detect_step(names: list) -> str:
    """Detect the ODB++ step directory name from a list of archive paths."""
    for n in names:
        nn = n.replace("\\", "/").lower()
        for prefix in ("/steps/", "steps/"):
            idx = nn.find(prefix)
            if idx >= 0:
                rest = nn[idx + len(prefix):]
                if rest and "/" in rest:
                    candidate = rest.split("/")[0]
                    if candidate:
                        return candidate
    return "pcb"


def _detect_step_dir(dir_path: str) -> str:
    """Detect step name from an unzipped directory layout."""
    for root, dirs, _ in os.walk(dir_path):
        for d in dirs:
            if d.lower() == "steps":
                steps_path = os.path.join(root, d)
                for entry in os.listdir(steps_path):
                    if os.path.isdir(os.path.join(steps_path, entry)):
                        return entry.lower()
    return "pcb"


def _read_archive(odb_path: str) -> Tuple[Dict[str, str], str]:
    """Open the archive (zip / tgz / dir) and cache matrix + features files.

    Returns:
        cache      : {normalised_lower_path: text_content}
        step_name  : detected step directory name (e.g. 'pcb')
    """
    cache: Dict[str, str] = {}
    step_name = "pcb"
    low = odb_path.lower()

    if os.path.isfile(odb_path) and low.endswith(".zip"):
        with zipfile.ZipFile(odb_path, "r") as zf:
            names = zf.namelist()
            step_name = _detect_step(names)
            for name in names:
                key = name.replace("\\", "/").lower()
                if _is_relevant(key):
                    try:
                        cache[key] = zf.read(name).decode("utf-8", errors="replace")
                    except Exception:
                        pass

    elif os.path.isfile(odb_path) and (
        low.endswith(".tgz") or low.endswith(".tar.gz") or low.endswith(".tar")
    ):
        mode = "r:gz" if low.endswith((".gz", ".tgz")) else "r"
        with tarfile.open(odb_path, mode) as tf:
            names = tf.getnames()
            step_name = _detect_step(names)
            for member in tf.getmembers():
                if not member.isfile():
                    continue
                key = member.name.replace("\\", "/").lower()
                if _is_relevant(key) and member.size < 30_000_000:
                    try:
                        f = tf.extractfile(member)
                        if f:
                            cache[key] = f.read().decode("utf-8", errors="replace")
                    except Exception:
                        pass

    elif os.path.isdir(odb_path):
        step_name = _detect_step_dir(odb_path)
        for root, _, files in os.walk(odb_path):
            for fname in files:
                if fname in ("features", "matrix"):
                    fpath = os.path.join(root, fname)
                    key = fpath.replace("\\", "/").lower()
                    if _is_relevant(key):
                        try:
                            with open(fpath, encoding="utf-8", errors="replace") as fh:
                                cache[key] = fh.read()
                        except Exception:
                            pass

    return cache, step_name


# ─────────────────────────────────────────────────────────────────────────────
# Layer discovery
# ─────────────────────────────────────────────────────────────────────────────

def _parse_silk_from_matrix(content: str) -> Dict[str, str]:
    """Parse ODB++ matrix file, return {side: layer_name} for silk layers."""
    in_layer = False
    name = ltype = ""
    silk_top = silk_bot = None

    for line in content.splitlines():
        line = line.strip()
        if line == "LAYER {":
            in_layer = True; name = ""; ltype = ""
        elif line == "}" and in_layer:
            if name and (
                ltype == "SILK_SCREEN"
                or "silk" in name.lower()
                or "overlay" in name.lower()
            ):
                n = name.lower()
                is_top = any(k in n for k in ("top", "f.", "top_overlay",
                                               "silkscreen_top", "silk_top"))
                is_bot = any(k in n for k in ("bot", "b.", "bottom",
                                               "silkscreen_bot", "silk_bot"))
                if is_top and not silk_top:
                    silk_top = name
                elif is_bot and not silk_bot:
                    silk_bot = name
                elif not is_top and not is_bot:
                    if not silk_top:
                        silk_top = name
                    elif not silk_bot:
                        silk_bot = name
            in_layer = False
        elif in_layer and "=" in line:
            k, _, v = line.partition("=")
            k = k.strip().upper(); v = v.strip()
            if k == "NAME":
                name = v
            elif k == "TYPE":
                ltype = v.upper()

    result: Dict[str, str] = {}
    if silk_top:
        result["top"] = silk_top
    if silk_bot:
        result["bot"] = silk_bot
    return result


def _find_silk_by_folder(cache: Dict[str, str]) -> Dict[str, str]:
    """Fallback: discover silk layers by scanning layer folder names."""
    silk_top = silk_bot = None
    for key in cache:
        if "/layers/" not in key:
            continue
        parts = key.split("/layers/")
        if len(parts) < 2:
            continue
        layer = parts[1].split("/")[0]
        if "silk" in layer or "overlay" in layer:
            n = layer.lower()
            is_bot = any(k in n for k in ("bot", "b.", "bottom"))
            is_top = any(k in n for k in ("top", "f.")) or not is_bot
            if is_top and not silk_top:
                silk_top = layer
            elif is_bot and not silk_bot:
                silk_bot = layer

    result: Dict[str, str] = {}
    if silk_top:
        result["top"] = silk_top
    if silk_bot:
        result["bot"] = silk_bot
    return result


def _get_layer_features(
    cache: Dict[str, str],
    step_name: str,
    layer_name: str,
) -> Optional[str]:
    """Return the text content of a layer's features file, or None."""
    needle = f"/layers/{layer_name.lower()}/features"
    for key, content in cache.items():
        if needle in key:
            return content
    return None


# ─────────────────────────────────────────────────────────────────────────────
# Feature parser
# ─────────────────────────────────────────────────────────────────────────────

_RE_SYM  = re.compile(r"^\$(\d+)\s+(\S+)")
_RE_RND  = re.compile(r"^r([\d.]+)$")
_RE_SQ   = re.compile(r"^s([\d.]+)$")
_RE_RECT = re.compile(r"^rect([\d.]+)x([\d.]+)")


def _parse_features_simple(content: str) -> Tuple[dict, list, list]:
    """Parse an ODB++ features file.

    Returns:
        syms  : {idx: (w_mm, h_mm)} – symbol dimensions in mm
        lines : [(x1, y1, x2, y2, sym_idx)] – coordinates in mm
        pads  : [(x, y, sym_idx)] – coordinates in mm
    """
    # Pass 1 — detect board units from file header (first 20 lines)
    inch_mode = False
    for raw_line in content.splitlines()[:20]:
        s = raw_line.strip().upper()
        if s.startswith("UNITS") and "INCH" in s:
            inch_mode = True
            break
        if re.match(r'^U\s+INCH', s):
            inch_mode = True
            break

    c2mm = 25.4 if inch_mode else 1.0   # raw coordinate → mm

    syms:  dict = {}
    lines: list = []
    pads:  list = []
    in_features = False

    for raw in content.splitlines():
        ln = raw.strip()
        if not ln:
            continue
        if "#Layer features" in raw:
            in_features = True

        # Symbol table entries — appear before AND after #Layer features
        if ln.startswith("$"):
            m = _RE_SYM.match(ln)
            if m:
                idx = int(m.group(1))
                sn = m.group(2).lower()
                w = h = 0.1  # default 0.1 mm
                mr = _RE_RND.match(sn)
                ms = _RE_SQ.match(sn)
                mc = _RE_RECT.match(sn)
                if mr:
                    d = float(mr.group(1))
                    v = d * 0.0254 if inch_mode else d / 1000.0
                    w = h = max(0.01, v)
                elif ms:
                    d = float(ms.group(1))
                    v = d * 0.0254 if inch_mode else d / 1000.0
                    w = h = max(0.01, v)
                elif mc:
                    wv = float(mc.group(1)) * (0.0254 if inch_mode else 0.001)
                    hv = float(mc.group(2)) * (0.0254 if inch_mode else 0.001)
                    w, h = max(0.01, wv), max(0.01, hv)
                syms[idx] = (w, h)
            continue

        if not in_features:
            continue

        if ln.startswith("L "):
            parts = ln.split(";")[0].split()
            if len(parts) >= 6:
                try:
                    lines.append((
                        float(parts[1]) * c2mm,
                        float(parts[2]) * c2mm,
                        float(parts[3]) * c2mm,
                        float(parts[4]) * c2mm,
                        int(parts[5]),
                    ))
                except (ValueError, IndexError):
                    pass

        elif ln.startswith("P "):
            parts = ln.split(";")[0].split()
            if len(parts) >= 4:
                try:
                    pads.append((
                        float(parts[1]) * c2mm,
                        float(parts[2]) * c2mm,
                        int(parts[3]),
                    ))
                except (ValueError, IndexError):
                    pass

    return syms, lines, pads


# ─────────────────────────────────────────────────────────────────────────────
# Cathode scoring
# ─────────────────────────────────────────────────────────────────────────────

def _score_pins(comp, lines: list, pads: list, syms: dict) -> Optional[int]:
    """Score which of comp.pins[0] vs comp.pins[1] is the cathode.

    Returns pin index (0 or 1), or None if the result is inconclusive.

    Algorithm
    ---------
    For each silk line feature within the search radius around the component:
      • Compute its midpoint and project onto the pin0→pin1 axis.
      • Weight by (line_length × line_width) boosted for perpendicular lines
        (a line perpendicular to the pad axis = the cathode band).
      • Accumulate weighted scores for pin[0] side and pin[1] side.

    The side with score_ratio >= _MIN_RATIO (default 55 %) wins.
    """
    p0, p1 = comp.pins[0], comp.pins[1]
    x0, y0 = p0.x, p0.y
    x1, y1 = p1.x, p1.y

    mx = (x0 + x1) / 2
    my = (y0 + y1) / 2
    dx = x1 - x0
    dy = y1 - y0
    span = math.hypot(dx, dy)
    if span < 0.3:
        return None  # pads too close — skip

    ux, uy = dx / span, dy / span     # unit vector from pin[0] to pin[1]
    search_r = span * 1.4 + 1.5       # search radius in mm
    deadzone  = span * 0.08            # 8 % of span — midpoint dead zone

    score = [0.0, 0.0]

    # ── Line features ─────────────────────────────────────────────────────
    for (lx1, ly1, lx2, ly2, sym_idx) in lines:
        lmx = (lx1 + lx2) / 2
        lmy = (ly1 + ly2) / 2
        if math.hypot(lmx - mx, lmy - my) > search_r:
            continue

        sym = syms.get(sym_idx, (0.1, 0.1))
        lw = sym[0]                        # line width in mm

        ldx = lx2 - lx1
        ldy = ly2 - ly1
        ll = math.hypot(ldx, ldy)
        if ll < 1e-6:
            ll = lw

        # Perpendicularity to pad axis (0 = parallel, 1 = perpendicular)
        if ll > 1e-6:
            along_frac = abs((ldx * ux + ldy * uy) / ll)
            perp_frac = math.sqrt(max(0.0, 1.0 - along_frac * along_frac))
        else:
            perp_frac = 0.5

        # Lines perpendicular to the pad axis get a 3.5× mass boost because
        # they are likely the cathode band rather than the body outline.
        perp_boost = 1.0 + 2.5 * perp_frac          # 1.0 … 3.5
        weight = max(ll, lw) * max(lw, 0.02) * perp_boost

        proj = (lmx - mx) * ux + (lmy - my) * uy
        if proj > deadzone:
            score[1] += weight
        elif proj < -deadzone:
            score[0] += weight

    # ── Pad-type features (filled symbols on silk) ─────────────────────────
    for (px, py, sym_idx) in pads:
        if math.hypot(px - mx, py - my) > search_r:
            continue
        sym = syms.get(sym_idx, (0.1, 0.1))
        weight = sym[0] * sym[1]
        proj = (px - mx) * ux + (py - my) * uy
        if proj > deadzone:
            score[1] += weight
        elif proj < -deadzone:
            score[0] += weight

    total = score[0] + score[1]
    if total < _MIN_MASS:
        return None  # not enough silk features

    ratio0 = score[0] / total
    ratio1 = score[1] / total

    if ratio0 >= _MIN_RATIO:
        return 0
    elif ratio1 >= _MIN_RATIO:
        return 1
    return None  # inconclusive


# ─────────────────────────────────────────────────────────────────────────────
# Main implementation
# ─────────────────────────────────────────────────────────────────────────────

def _detect_impl(odb_path: str, odb_comps: list) -> Dict[str, int]:
    cache, step_name = _read_archive(odb_path)
    if not cache:
        return {}

    # Find silk layer names
    matrix_content: Optional[str] = None
    for key, content in cache.items():
        if key.endswith("matrix/matrix"):
            matrix_content = content
            break

    silk_layers = _parse_silk_from_matrix(matrix_content) if matrix_content else {}
    if not silk_layers:
        silk_layers = _find_silk_by_folder(cache)
    if not silk_layers:
        return {}

    # Parse silk features per side
    silk_parsed: Dict[str, tuple] = {}  # side → (syms, lines, pads)
    for side, layer_name in silk_layers.items():
        content = _get_layer_features(cache, step_name, layer_name)
        if content:
            syms, lines, pads = _parse_features_simple(content)
            silk_parsed[side] = (syms, lines, pads)

    if not silk_parsed:
        return {}

    # Score each 2-pin diode/LED
    results: Dict[str, int] = {}
    for comp in odb_comps:
        if comp.comp_type not in ("diode", "led"):
            continue
        if len(comp.pins) != 2:
            continue

        side = comp.side  # "top" or "bot"
        data = (
            silk_parsed.get(side)
            or silk_parsed.get("top")
            or next(iter(silk_parsed.values()), None)
        )
        if not data:
            continue

        syms, lines, pads = data
        pin_idx = _score_pins(comp, lines, pads, syms)
        if pin_idx is not None:
            results[comp.ref] = pin_idx

    return results
